// 자동 생성 파일 — 직접 수정하지 말 것.
// 생성: scripts/build_hc_sections.py  (원본: public/hc-landing/index.html)
// AIWalker 랜딩페이지를 flow 가로 패널용 섹션으로 분할하고 CSS 를 .hc 로 스코프한 결과.

export const hcCss = ".hc /* 사이트 공통 웹폰트 (scripts/convert_fonts.py). flow 임베드/직접 접근 모두에서 적용 */\n@font-face{font-family:'S-Core Dream';src:url('/fonts/scdream-6.woff2') format('woff2');font-weight:600;font-display:swap}\n@font-face{font-family:'S-Core Dream';src:url('/fonts/scdream-8.woff2') format('woff2');font-weight:800;font-display:swap}\n@font-face{font-family:'Freesentation';src:url('/fonts/freesentation-4.woff2') format('woff2');font-weight:400;font-display:swap}\n@font-face{font-family:'Freesentation';src:url('/fonts/freesentation-6.woff2') format('woff2');font-weight:600;font-display:swap}\n@font-face{font-family:'Freesentation';src:url('/fonts/freesentation-7.woff2') format('woff2');font-weight:700;font-display:swap}\n.hc{\n  --bg:#FFFFFF;\n  --ink:#17232E;\n  --dark:#17232E;\n  --pine:#0B3FD8;\n  --ok:#2E9E68;\n  --warn:#E8A33A;\n  --risk:#D4553F;\n  --lime:#00CFF0;\n  --muted:#3A4956;\n  --line:#E4E8EC;\n  --card:#FFFFFF;\n  --r:24px;\n}\n.hc *{margin:0;padding:0;box-sizing:border-box}\n.hc{scroll-behavior:smooth}\n.hc{\n  font-family:'Freesentation',-apple-system,sans-serif;\n  background:var(--bg);color:var(--ink);line-height:1.6;\n  -webkit-font-smoothing:antialiased;\n}\n.hc /* 큰 제목은 사이트 공통 제목체(S-Core Dream) */\nh1, .hc h2, .hc h3, .hc .logo{font-family:'S-Core Dream','Freesentation',sans-serif}\n.hc /* 숫자·영문 라벨도 사이트 공통 본문체를 사용한다. */\n.mono{font-family:'Freesentation',sans-serif;font-variant-numeric:tabular-nums}\n.hc .wrap{width:100%;max-width:72rem;margin:0 auto;padding:0 3rem 0 6.5rem}\n.hc .eyebrow, .hc .f-num{\n  font-family:'Freesentation','Apple SD Gothic Neo',sans-serif;\n  font-size:16px;font-weight:700;line-height:1.5;letter-spacing:.18em;color:var(--pine);\n  text-transform:uppercase;\n}\n.hc .eyebrow{margin-bottom:16px}\n.hc section{padding:80px 0}\n.hc /* ── photo frame system ──\n   .photo 안에 <img src=\"images/…\">를 넣으세요.\n   이미지가 없으면 안내 라벨이 있는 듀오톤 대체 화면이 표시됩니다. */\n.photo{\n  position:relative;overflow:hidden;border-radius:var(--r);\n  background:\n    radial-gradient(120% 90% at 20% 10%, #2E9E68 0%, transparent 55%),\n    radial-gradient(120% 100% at 90% 90%, #CDEA6A33 0%, transparent 50%),\n    linear-gradient(160deg,#123B2E 0%,#0F2A22 70%);\n}\n.hc .photo img{\n  position:absolute;inset:0;width:100%;height:100%;object-fit:cover;display:block;\n}\n.hc .photo .ph-label{\n  position:absolute;inset:0;display:flex;flex-direction:column;gap:8px;\n  align-items:center;justify-content:center;text-align:center;color:#CFE3D6;\n  padding:24px;z-index:0;\n}\n.hc .photo .ph-label .cam{font-size:26px;opacity:.9}\n.hc .photo .ph-label b{font-size:13px;color:#fff;letter-spacing:.02em}\n.hc .photo .ph-label span{font-size:11px;opacity:.75;max-width:260px;line-height:1.5}\n.hc .photo::after{ /* 사진 위 은은한 그린 톤(듀오톤 무드) */\n  content:\"\";position:absolute;inset:0;pointer-events:none;\n  background:linear-gradient(180deg,rgba(15,42,34,0) 55%,rgba(15,42,34,.38) 100%);\n}\n.hc /* ── nav ── */\nnav{\n  position:sticky;top:0;z-index:50;background:rgba(255,255,255,.9);\n  backdrop-filter:blur(12px);border-bottom:1px solid var(--line);\n}\n.hc .nav-in{\n  max-width:1180px;margin:0 auto;padding:14px 28px;\n  display:flex;align-items:center;gap:26px;\n}\n.hc .logo{font-weight:900;font-size:17px;letter-spacing:-.01em}\n.hc .logo small{font-weight:500;color:var(--muted);font-size:12px;margin-left:8px}\n.hc .nav-links{display:flex;gap:22px;margin-left:auto}\n.hc .nav-links a{font-size:13.5px;font-weight:700;color:var(--ink);text-decoration:none}\n.hc .nav-links a:hover{color:var(--pine)}\n.hc .live{display:flex;align-items:center;gap:7px;font-size:12px;font-weight:700;color:var(--muted)}\n.hc .live .dot{width:8px;height:8px;border-radius:50%;background:var(--risk);animation:blink 1.6s infinite}\n@keyframes blink{0%,100%{opacity:1}50%{opacity:.35}}\n.hc .btn{\n  display:inline-block;background:var(--pine);color:#fff;text-decoration:none;\n  font-size:16px;font-weight:600;padding:12px 22px;border-radius:999px;\n  transition:transform .15s, background .15s;\n}\n.hc .btn:hover{background:#0026E6;transform:translateY(-1px)}\n.hc .btn.ghost{background:transparent;color:var(--ink);border:1.5px solid var(--ink)}\n.hc .btn.ghost:hover{background:var(--ink);color:#fff}\n.hc .btn.lime{background:var(--lime);color:var(--ink)}\n.hc .btn.lime:hover{background:#fff}\n.hc /* ── hero ── */\n.hero{padding:96px 0 48px}\n.hc .hero-grid{display:grid;grid-template-columns:1fr 1.05fr;gap:40px;align-items:start}\n.hc .hero h1{font-size:clamp(40px,4.4vw,56px);font-weight:800;line-height:1.15;letter-spacing:-.035em}\n.hc .hero h1 .frame{position:relative;display:inline-block;padding:0;color:var(--pine)}\n.hc .hero h1 .frame::before, .hc .hero h1 .frame::after, .hc .hero h1 .frame b::before, .hc .hero h1 .frame b::after{\n  display:none;\n}\n.hc .hero h1 .frame::before{top:-3px;left:-3px;border-right:none;border-bottom:none}\n.hc .hero h1 .frame::after{top:-3px;right:-3px;border-left:none;border-bottom:none}\n.hc .hero h1 .frame b::before{bottom:-3px;left:-3px;border-right:none;border-top:none}\n.hc .hero h1 .frame b::after{bottom:-3px;right:-3px;border-left:none;border-top:none}\n.hc .hero p.sub{margin:24px 0 28px;font-size:18px;line-height:1.85;color:var(--muted);max-width:48rem}\n.hc .hero p.sub b{color:var(--ink);font-weight:700}\n.hc .cta-row{display:flex;gap:12px;flex-wrap:wrap}\n.hc /* hero photo + floating UI */\n.hero-photo{position:relative}\n.hc .hero-photo .photo{aspect-ratio:4/4.6;box-shadow:0 24px 64px rgba(23,35,46,.16)}\n.hc .chip{\n  position:absolute;background:rgba(255,255,255,.96);border:1px solid var(--line);\n  border-radius:16px;padding:11px 16px;box-shadow:0 12px 32px rgba(16,36,29,.16);\n  font-size:12px;font-weight:700;z-index:2;animation:bob 4.5s ease-in-out infinite;\n}\n.hc .chip .v{font-size:17px;font-weight:700;color:var(--pine)}\n.hc .chip.dark{background:rgba(23,35,46,.94);border-color:transparent;color:#E4E8EC}\n.hc .chip.dark .v{color:var(--lime)}\n.hc .chip.c1{top:7%;left:-4%}\n.hc .chip.c2{top:38%;right:-5%;animation-delay:.8s}\n.hc .chip.c3{bottom:7%;left:6%;animation-delay:1.6s}\n.hc .chip .lamps{display:flex;gap:6px;margin-top:5px}\n.hc .chip .lamp{width:22px;height:22px;border-radius:50%}\n.hc .chip .lamp.g{background:var(--ok);box-shadow:0 0 0 4px rgba(46,158,104,.25)}\n.hc .chip .lamp.y{background:var(--warn);opacity:.3}\n.hc .chip .lamp.r{background:var(--risk);opacity:.3}\n@keyframes bob{0%,100%{transform:translateY(0)}50%{transform:translateY(-9px)}}\n@media (prefers-reduced-motion:reduce){.hc .chip, .hc .live .dot, .hc .tick-track{animation:none!important}}\n.hc /* ── ticker ── */\n.ticker{\n  border-top:1px solid var(--line);border-bottom:1px solid var(--line);\n  overflow:hidden;background:#F4F6F8;padding:13px 0;\n}\n.hc .tick-track{display:flex;width:max-content;animation:scroll 28s linear infinite}\n@keyframes scroll{to{transform:translateX(-50%)}}\n.hc .tick-item{\n  display:flex;align-items:center;padding:0 26px;\n  font-size:14.5px;font-weight:900;color:var(--ink);white-space:nowrap;\n}\n.hc .tick-item::after{content:\"●\";font-size:7px;margin-left:26px;opacity:.5}\n.hc /* ── features ── */\n#features .head{max-width:640px;margin-bottom:56px}\n.hc #features h2{font-size:clamp(32px,3.6vw,48px);font-weight:800;letter-spacing:-.03em;line-height:1.25}\n.hc .feature{\n  display:grid;grid-template-columns:1fr 1.15fr;gap:44px;align-items:center;\n  padding:48px 0;border-top:1px solid var(--line);\n}\n.hc .feature.flip{grid-template-columns:1.15fr 1fr}\n.hc .feature.flip .f-media{order:-1}\n.hc .f-num{margin-bottom:10px}\n.hc .f-text h3{font-size:clamp(24px,2.2vw,28px);font-weight:800;letter-spacing:-.025em;line-height:1.35;margin-bottom:14px}\n.hc .f-text p{font-size:18px;line-height:1.85;color:var(--muted);max-width:48rem}\n.hc .f-text p b{color:var(--ink)}\n.hc .f-copy-line{display:inline-block;white-space:nowrap}\n.hc .f-tags{display:flex;gap:8px;flex-wrap:wrap;margin-top:18px}\n.hc .f-tag{font-size:14px;font-weight:600;border:1px solid var(--line);border-radius:999px;padding:6px 13px;color:var(--ink)}\n.hc .f-media{position:relative}\n.hc .f-media .photo{aspect-ratio:16/11}\n.hc /* 사진 위 오버레이 UI */\n.ov{\n  position:absolute;z-index:2;background:rgba(255,255,255,.96);\n  border-radius:14px;padding:10px 14px;box-shadow:0 12px 30px rgba(16,36,29,.2);\n  font-size:11.5px;font-weight:700;\n}\n.hc .ov.dark{background:rgba(15,42,34,.94);color:#CFE3D6}\n.hc .ov .big{font-size:15px;font-weight:900;color:var(--ink)}\n.hc .ov.dark .big{color:#fff}\n.hc .ov .accent{color:var(--pine)}\n.hc .ov.dark .accent{color:var(--lime)}\n.hc .ov-lamps{display:flex;gap:8px;align-items:center}\n.hc .ov-lamps .lamp{width:30px;height:30px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:9px;font-weight:900;color:#fff}\n.hc .ov-lamps .g{background:var(--ok)}\n.hc .ov-lamps .y{background:var(--warn);opacity:.35}\n.hc .ov-lamps .r{background:var(--risk);opacity:.35}\n.hc .spark{display:block;margin-top:6px}\n.hc /* ── stats ── */\n.stats-band{background:var(--dark);color:#fff}\n.hc .stats-band .eyebrow{color:var(--lime)}\n.hc .stats-band h2{font-size:clamp(26px,3.4vw,38px);font-weight:900;letter-spacing:-.02em;margin-bottom:44px;line-height:1.3}\n.hc .stat-grid{display:grid;grid-template-columns:repeat(5,1fr);gap:1px;background:rgba(255,255,255,.14);border-radius:18px;overflow:hidden}\n.hc .stat{background:var(--dark);padding:26px 22px}\n.hc .stat .v{font-family:'Freesentation',sans-serif;font-size:38px;font-weight:700;color:var(--lime);line-height:1.1;font-variant-numeric:tabular-nums}\n.hc .stat .v.compact{font-size:28px;letter-spacing:-.02em;white-space:nowrap}\n.hc .stat .v small{font-size:19px}\n.hc .stat .k{font-size:14px;line-height:1.6;color:#AFC5BB;margin-top:10px}\n.hc /* ── timeline (사진 썸네일 포함) ── */\n.tl{margin-top:48px;position:relative}\n.hc .tl::before{content:\"\";position:absolute;left:9px;top:8px;bottom:8px;width:2px;background:var(--line)}\n.hc .tl-item{position:relative;padding:0 0 40px 44px;display:grid;grid-template-columns:1fr 220px;gap:24px;align-items:start}\n.hc .tl-item:last-child{padding-bottom:0}\n.hc .tl-item::before{\n  content:\"\";position:absolute;left:0;top:5px;width:20px;height:20px;border-radius:50%;\n  background:var(--bg);border:2.5px solid var(--pine);\n}\n.hc .tl-item.done::before{background:var(--pine)}\n.hc .tl-item.now::before{background:var(--lime);border-color:var(--ink);box-shadow:0 0 0 6px rgba(205,234,106,.4)}\n.hc .tl-date{font-family:'Freesentation',sans-serif;font-size:13px;font-weight:700;letter-spacing:.1em;color:var(--muted);text-transform:uppercase;font-variant-numeric:tabular-nums}\n.hc .tl-date .flag{color:var(--pine);font-weight:900}\n.hc .tl-item.now .tl-date .flag{background:var(--lime);color:var(--ink);padding:2px 8px;border-radius:6px}\n.hc .tl-item h3{font-size:21px;font-weight:900;margin:4px 0 4px;letter-spacing:-.01em}\n.hc .tl-item p{font-size:14px;color:var(--muted);max-width:520px}\n.hc .tl-thumb .photo{aspect-ratio:16/10;border-radius:16px}\n.hc .tl-thumb .ph-label .cam{font-size:18px}\n.hc .tl-thumb .ph-label b{font-size:11px}\n.hc .tl-thumb .ph-label span{display:none}\n.hc /* ── FAQ ── */\n.faq details{border-top:1px solid var(--line)}\n.hc .faq details:last-child{border-bottom:1px solid var(--line)}\n.hc .faq summary{\n  cursor:pointer;list-style:none;display:flex;justify-content:space-between;align-items:center;\n  padding:22px 4px;font-size:17px;font-weight:900;letter-spacing:-.01em;\n}\n.hc .faq summary::-webkit-details-marker{display:none}\n.hc .faq summary .plus{font-family:'Freesentation',sans-serif;font-size:22px;color:var(--pine);transition:transform .25s;flex-shrink:0;margin-left:16px}\n.hc .faq details[open] summary .plus{transform:rotate(45deg)}\n.hc .faq .a{padding:0 4px 24px;font-size:14.5px;color:var(--muted);max-width:720px}\n.hc .faq .a b{color:var(--ink)}\n.hc /* ── CTA (사진 배경) ── */\n.cta-band{\n  position:relative;border-radius:28px;overflow:hidden;color:#fff;text-align:center;\n}\n.hc .cta-band .photo{position:absolute;inset:0;border-radius:0;aspect-ratio:auto}\n.hc .cta-band .photo::after{background:linear-gradient(180deg,rgba(15,42,34,.72),rgba(15,42,34,.82))}\n.hc .cta-in{position:relative;z-index:2;padding:72px 48px}\n.hc .cta-band h2{font-size:clamp(26px,3.6vw,40px);font-weight:900;letter-spacing:-.02em;line-height:1.3}\n.hc .cta-band p{color:#CFE3D6;margin:14px 0 28px;font-size:15px}\n.hc footer{padding:36px 0 44px;font-size:12.5px;color:var(--muted)}\n.hc .foot-in{display:flex;justify-content:space-between;gap:16px;flex-wrap:wrap}\n@media(max-width:920px){.hc .wrap{padding:0 24px}.hc .hero{padding-top:80px}.hc section{padding:64px 0}.hc .nav-links, .hc .live{display:none}.hc .hero-grid{grid-template-columns:1fr}.hc .chip.c1{left:2%}.hc .chip.c2{right:2%}.hc .feature, .hc .feature.flip{grid-template-columns:1fr;gap:24px}.hc .feature.flip .f-media{order:0}.hc .f-copy-line{display:inline;white-space:normal}.hc .f-copy-break{display:none}.hc .stat-grid{grid-template-columns:1fr 1fr}.hc .stat:last-child{grid-column:1/-1}.hc .tl-item{grid-template-columns:1fr}.hc .cta-in{padding:48px 24px}}";

